function defaultSrs(now: number) {
  return { ease: 2.5, interval: 0, dueAt: now, reps: 0 }
}

export function buildParagraph65_25Sets(createdAt = Date.now()): TranslationSet[] {
  const sets: TranslationSet[] = []

  for (const genre of Object.keys(DATA) as TopicGenre[]) {
    const rows = DATA[genre]
    if (rows.length !== 25) {
      throw new Error(`paragraph65_25: ${genre} has ${rows.length} sentences, expected 25`)
    }
    const setId = `tr-p65-${genre}`
    sets.push({
      id: setId,
      title: TITLES[genre],
      category: 'paragraph_65',
      genre: genre as TranslationGenre,
      cefr: 'B1',
      createdAt,
      sentences: rows.map((row, i) => {
        const [vi, en, hint, difficulty] = row
        const n = String(i + 1).padStart(2, '0')
        return {
          id: `${setId}-s${n}`,
          vi,
          en,
          hint,
          difficulty: difficulty ?? 'medium',
          srsState: defaultSrs(createdAt),
        }
      }),
    })
  }

  return sets
}

export const PARAGRAPH_65_GENRE_IDS = Object.keys(DATA) as TranslationGenre[]
